sql_query:
SELECT "Type of therapy"
FROM clinical_trials
WHERE "Cancer type" = 'Hepatocellular';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Type of therapy" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Hepatocellular'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_is_combination(source_value) AS "is_combination"
FROM base;
